SELECT a.id, w.title AS work_title, wf.file_url AS work_thumbnail, m.nickname AS seller_nickname, a.current_price, a.bid_count, a.closing_at, a.status FROM tbl_auction a JOIN tbl_work w ON a.work_id = w.id JOIN tbl_member m ON a.seller_id = m.id LEFT JOIN tbl_work_file wf ON wf.work_id = a.work_id AND wf.sort_order = 0
AND a.status = #{status}
AND a.seller_id = #{sellerId}
AND w.title ILIKE '%' || #{keyword} || '%'
ORDER BY a.created_datetime DESC LIMIT #{size} OFFSET (#{page} - 1) * #{size}

SELECT COUNT(*)
FROM tbl_auction a
JOIN tbl_work w ON a.work_id = w.id


        AND a.status = #{status}


        AND a.seller_id = #{sellerId}


        AND w.title ILIKE '%' || #{keyword} || '%'

SELECT EXISTS (
    SELECT 1 FROM tbl_auction_wishlist
    WHERE member_id = #{memberId}
      AND auction_id = #{auctionId}
)

